  "verses": [
    {
      "n": 19,
      "column": "left",
      "text": "Un redſi / ſeptix zittas\nGohwis uſkahpe pehz tahm lee-\nfas/ un fohti nejaunkas/ un ar fa-\nkaltufchahm Meeſahn/es ne eſmu\ntik nejaunkas/ kaſchahs / wiſſa E-\ngiptes-Semmê redſejis.\n"
    },
    {
      "n": 20,
      "column": "left",
      "text": "Un tahs fakaltufchas un\nnejaunkas Gohwis / eerihja tahs\nfeptix pirmastreknasGohwis.\n"
    },
    {
      "n": 21,
      "column": "left",
      "text": "Un kad tahs bija no win-\nxeem eerihtas/ ne warreja paſiht/\nka tee winxeem Kuugôs bija / un\ntee iſluhkojahs nejauki / ta patt/\nka pirmak: tad es atmohdohs.\n"
    },
    {
      "n": 22,
      "column": "left",
      "text": "Pehz to / redſeju es farwâ\nSapni/ un rangi/ ſeptin Wahr-\npas isauge no weenu Steebri /\npilnas un dischenas.\n"
    },
    {
      "n": 23,
      "column": "left",
      "text": "Un rangi / ſeptin fakaltu-\nchas teewas/ un no Auſtrina fa-\ndeggufchas Wahrpas isplauka\npehz tahm.\n"
    },
    {
      "n": 24,
      "column": "left",
      "text": "Un tahs ſeptix teewas\nWahrpas / eerihje tahs ſeptix Di-\nschenas Wahrpas/ un es eſmu to\nteem Sihlinekeem ſazzijis/ bet ne\nweens irr/ kas to warr iſtahſtiht.\n"
    },
    {
      "n": 25,
      "column": "left",
      "text": "Tad ſazzija Jahſeps uhs\nWaraii : Tas Sapnis Waraiis\nirr weenahds / DEews irr Wara-\ntun ſinnamu darrijs/ ko tas ap-\nrehmees darriht.\n"
    },
    {
      "n": 26,
      "column": "left",
      "text": "Tahs ſeptix krahfnas Goh-\nwis irr ſeptix Gaddi / un tahs\nſeptix dischenas Wahrpas / irr\nſeptix Gaddi / tas Sapnis irr\nweenahds.\n"
    },
    {
      "n": 27,
      "column": "right",
      "text": "Un tahs ſeptix fa-\nchas un nejaunkas Gohwis\npehz tahm uſkahpe / irr\nGaddi / un tahs ſeptix te-\nun no Auſtrina nodegg\nWahrpas/ buhs ſeptix B\nGaddi.\n"
    },
    {
      "n": 28,
      "column": "right",
      "text": "Schis irr tas Wah-\nes us Warait runnajis\nDEews irr Waraim para-\nko winsch irr apnehmees.\n"
    },
    {
      "n": 29,
      "column": "right",
      "text": "Redſi / ſeptix itt a\nGaddi nahks pahr wiſſu\ntes-Semini.\n"
    },
    {
      "n": 30,
      "column": "right",
      "text": "Bet pehz teem nah-\ntin Badda-Gaddi / tad ta\nSuitums Egiptes - Semm\nmirſts/ un tas Bads flati-\ndihs to Semini.\n"
    },
    {
      "n": 31,
      "column": "right",
      "text": "Un tas Suitums n\nnopraſts tai Seimmê / p\nta pehznahkama Badda /\nbuhs pahrleeſu gruhts.\n"
    },
    {
      "n": 32,
      "column": "right",
      "text": "Un par to/ ka tas\nWaraiim diwireifi irr rah-\ntas irr tapehz/ ka Deews t\napnehmees / un Deews fie\nto darriht.\n"
    },
    {
      "n": 33,
      "column": "right",
      "text": "Un nu laid Waraii-\npehz weenu faſrattigu/ un\nWihrn / un eezelt to pahr\ntes-Semmi.\n"
    },
    {
      "n": 34,
      "column": "right",
      "text": "Laid Waraiiſta da-\neezeit uſraugus pahr to S\nun reimm to peektu Teefu\ngiptes-Semmes/ eekſch tee-\ntix baggateem Gaddeem /\ntee faſrahj wiſſadu Barrib\nſcheem nahfameem aug\nGaddeem.\n"
    }
  ],
  "confidence": "high",
  "notes": ""
}
